// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package neptuneimport ("context""time""github.com/aws/aws-sdk-go/service/neptune""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry")const (// Maximum amount of time to wait for an EventSubscription to return DeletedEventSubscriptionDeletedTimeout = 10 * time.Minute// Maximum amount of time to wait for an DBClusterEndpoint to return AvailableDBClusterEndpointAvailableTimeout = 10 * time.Minute// Maximum amount of time to wait for an DBClusterEndpoint to return DeletedDBClusterEndpointDeletedTimeout = 10 * time.Minute)// WaitEventSubscriptionDeleted waits for a EventSubscription to return Deletedfunc WaitEventSubscriptionDeleted(ctx context.Context, conn *neptune.Neptune, subscriptionName string) (*neptune.EventSubscription, error) {stateConf := &retry.StateChangeConf{Pending: []string{"deleting"},Target:  []string{EventSubscriptionStatusNotFound},Refresh: StatusEventSubscription(ctx, conn, subscriptionName),Timeout: EventSubscriptionDeletedTimeout,}outputRaw, err := stateConf.WaitForStateContext(ctx)if v, ok := outputRaw.(*neptune.EventSubscription); ok {return v, err}return nil, err}// WaitDBClusterEndpointAvailable waits for a DBClusterEndpoint to return Availablefunc WaitDBClusterEndpointAvailable(ctx context.Context, conn *neptune.Neptune, id string) (*neptune.DBClusterEndpoint, error) {stateConf := &retry.StateChangeConf{Pending: []string{"creating", "modifying"},Target:  []string{"available"},Refresh: StatusDBClusterEndpoint(ctx, conn, id),Timeout: DBClusterEndpointAvailableTimeout,}outputRaw, err := stateConf.WaitForStateContext(ctx)if v, ok := outputRaw.(*neptune.DBClusterEndpoint); ok {return v, err}return nil, err}// WaitDBClusterEndpointDeleted waits for a DBClusterEndpoint to return Deletedfunc WaitDBClusterEndpointDeleted(ctx context.Context, conn *neptune.Neptune, id string) (*neptune.DBClusterEndpoint, error) {stateConf := &retry.StateChangeConf{Pending: []string{"deleting"},Target:  []string{},Refresh: StatusDBClusterEndpoint(ctx, conn, id),Timeout: DBClusterEndpointDeletedTimeout,}outputRaw, err := stateConf.WaitForStateContext(ctx)if v, ok := outputRaw.(*neptune.DBClusterEndpoint); ok {return v, err}return nil, err}